import time
import collections

class RateLimiter:
    def __init__(self, rate_limit, time_period):
        self.rate_limit = rate_limit
        self.time_period = time_period
        self._request_timestamps = collections.deque()

    def _wait_for_slot(self):
        while True:
            now = time.time()
            while self._request_timestamps and self._request_timestamps[0] <= now - self.time_period:
                self._request_timestamps.popleft()

            if len(self._request_timestamps) < self.rate_limit:
                self._request_timestamps.append(now)
                break
            else:
                oldest_request_time = self._request_timestamps[0]
                next_available_time = oldest_request_time + self.time_period
                time_to_wait = next_available_time - now
                if time_to_wait > 0:
                    time.sleep(time_to_wait)

    def make_api_request(self, url, data=None, method="GET"):
        self._wait_for_slot()

        print(f"[{time.time():.2f}] Making {method} request to {url} with data {data}")

        return {"status": "success", "url": url, "timestamp": time.time()}
